function FadasIcon({ name, size = 24, tone = 'duo' }) {
  const inner = window.FADAS_ICON_PATHS[name];
  if (!inner) return null;
  // Two tones:
  //   'duo'   — ros\u00e9-gold multi-stop gradient stroke/fill, gold gradient on hover (canonical Fadas)
  //   'solid' — single ros\u00e9 stroke color #c47860 normal, single gold #c8a840 hover (v1 drawer simplification)
  if (tone === 'solid') {
    // Color comes from CSS rule .fadas-icon-solid { color: #c47860 } in index.html
    // so a parent :hover rule (e.g. .drawer-item:hover .fadas-icon-solid) can override.
    return (
      <span className="fadas-icon fadas-icon-solid" style={{ position: 'relative', display: 'inline-block', width: size, height: size, flexShrink: 0 }}>
        <svg viewBox="0 0 256 256" width={size} height={size} style={{ display: 'block' }} dangerouslySetInnerHTML={{ __html: inner }}/>
      </span>
    );
  }
  const baseStyle = { position: 'absolute', inset: 0, width: size, height: size, transition: 'opacity 0.35s ease' };
  return (
    <span className="fadas-icon fadas-icon-duo" style={{ position: 'relative', display: 'inline-block', width: size, height: size, flexShrink: 0 }}>
      <svg className="rose" viewBox="0 0 256 256" style={baseStyle} dangerouslySetInnerHTML={{ __html: inner }}/>
      <svg className="gold" viewBox="0 0 256 256" style={{ ...baseStyle, opacity: 0 }} dangerouslySetInnerHTML={{ __html: inner }}/>
    </span>
  );
}

window.FadasIcon = FadasIcon;
